class Solution {
    public String reverseParentheses(String s) {
        StringBuilder sb = new StringBuilder();
        for (char c : s.toCharArray()) {
            if (c == ')') {
                sb.reverse();
            } else if (c != '(') {
                sb.append(c);
            }
        }
        return sb.toString();
    }
}
